insert into public.indicator_field_catalog (tenant_id,module_key,base_table,field_key,label,data_type,semantic_type,allowed_operations,allowed_filters,is_dimension,is_measure)
select null,module_key,base_table,field_key,label,data_type,semantic_type,allowed_operations,allowed_filters,is_dimension,is_measure from field_seed
on conflict (tenant_id, base_table, field_key) do update set module_key=excluded.module_key, label=excluded.label, data_type=excluded.data_type, semantic_type=excluded.semantic_type, allowed_operations=excluded.allowed_operations, allowed_filters=excluded.allowed_filters, is_dimension=excluded.is_dimension, is_measure=excluded.is_measure, is_active=true, updated_at=now();
